# Dependency Management Script

"""
This script assists in managing Python dependency specifications for consistent versions across development and production environments.
It helps in generating and updating `requirements.txt` with hashes or managing `pyproject.toml` and `poetry.lock` files for Poetry users.
"""

import subprocess
import sys
import os

def generate_requirements_with_hashes(env=''):
    """Generate a requirements.txt file with hashes."""
    if env:
        subprocess.run([sys.executable, '-m', 'pip', 'freeze', '--hash=sha256'], stdout=open('requirements.txt', 'w'))
    else:
        subprocess.run([sys.executable, '-m', 'pip', 'freeze'], stdout=open('requirements.txt', 'w'))
    print("Generated requirements.txt with hashes.")

def update_requirements():
    """Update requirements.txt based on the environment."""
    subprocess.run([sys.executable, '-m', 'pip', 'install', '-r', 'requirements.txt'])
    subprocess.run([sys.executable, '-m', 'pip', 'freeze', '--hash=sha256'], stdout=open('requirements.txt', 'w'))
    print("Updated requirements.txt.")

def install_poetry():
    """Install Poetry if not already installed."""
    try:
        subprocess.run(['poetry', '--version'], check=True)
    except subprocess.CalledProcessError:
        subprocess.run(['pip', 'install', 'poetry'])
    print("Poetry is installed.")

def generate_pyproject():
    """Generate a new pyproject.toml for a project."""
    subprocess.run(['poetry', 'init', '--no-interaction'])
    print("Generated pyproject.toml.")

def update_poetry_lock():
    """Update the poetry.lock file from pyproject.toml."""
    subprocess.run(['poetry', 'update'])
    print("Updated poetry.lock.")

def main():
    """Main function to manage dependencies."""
    if not os.path.exists('requirements.txt'):
        print("Generating initial requirements.txt...")
        generate_requirements_with_hashes()
    else:
        print("Updating existing requirements.txt...")
        update_requirements()

    # Uncomment the following lines if using Poetry
